    "0e315058": {"text":"Arrosez le vin.","hash":"h1-bf1af6e6"},
    "0e3840fa": {"text":"Aucun enfant vivant. Sans héritier, votre histoire se termine avec vous.","hash":"h1-eccadb98"},
    "0e471495": {"text":"Je connaissais les secrets de chacun et j’emportais les meilleurs.","hash":"h1-65bbab01"},
